```javascript
// Simple application with security best practices
const express = require('express');
const helmet = require('helmet');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');
const app = express();

// Security Middleware
app.use(helmet()); // Set security HTTP headers
app.use(morgan('combined')); // Request logging

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.'
});
app.use(limiter);

// Body parser middleware (for POST/PUT requests)
app.use(express.json({ limit: '1mb' })); // Limit payload size
app.use(express.urlencoded({ extended: false, limit: '1mb' }));

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  try {
    // Sanitize and validate query parameters
    const { page = '1', limit = '10' } = req.query;

    // Validate numeric inputs
    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);

    if (isNaN(pageNum) || isNaN(limitNum) || pageNum < 1 || limitNum < 1 || limitNum > 100) {
      return res.status(400).json({ 
        error: 'Invalid pagination parameters',
        details: 'page and limit must be positive integers, limit max 100'
      });
    }

    req.validatedQuery = { page: pageNum, limit: limitNum };
    next();
  } catch (error) {
    res.status(400).json({ error: 'Invalid request parameters' });
  }
};

// Health check endpoint (no validation needed)
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    res.status(500).json({ error: 'Health check failed' });
  }
});

// Users endpoint with validation
app.get('/users', validateQueryParams, (req, res) => {
  try {
    const { page, limit } = req.validatedQuery;

    // Mock data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Pagination logic
    const start = (page - 1) * limit;
    const end = start + limit;
    const paginatedUsers = users.slice(start, end);

    res.json({
      data: paginatedUsers,
      pagination: { page, limit, total: users.length }
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Failed to fetch users' });
  }
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Endpoint not found' });
});

// Global error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(err.status || 500).json({ 
    error: process.env.NODE_ENV === 'production' 
      ? 'Internal server error' 
      : err.message 
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

module.exports = app;
```

